// statusBadgeFor renders a small badge showing whether an integration tab is configured.
func statusBadgeFor(d layouts.PageData, key string) string {
	for _, st := range d.Integrations {
		if st.Key == key {
			if st.Configured {
				return "ok"
			}
			if st.Required {
				return "req"
			}
			return "miss"
		}
	}
	return ""
}

func tooltipFor(d layouts.PageData, keys ...string) string {
	var msg string
	for _, k := range keys {
		for _, st := range d.Integrations {
			if st.Key != k {
				continue
			}
			if st.Configured {
				msg += "✓ " + st.Name + ": sudah dikonfigurasi\n"
			} else {
				msg += "⚠ " + st.Name + ": butuh "
				for i, m := range st.Missing {
					if i > 0 {
						msg += ", "
					}
					msg += m
				}
				msg += "\n"
			}
		}
	}
	return msg
}

